679	                inB1 = *__SIMD64(pB)++;
680	                sum = NDS_DSP_SMAQA_SU(sum, inA1, inB1);
681	                colCnt--;
682	            }
683	            //sum up the high and low part results (SIMD results)
684	            sum = (q31_t)(sum >> 32) + (q31_t)sum;
685	
686	            colCnt = 3 * ker_dim * ker_dim & 0x7;
687	            while (colCnt)
688	            {
689	                q7_t inA1 = *pA++;
690	                u8_t inB1 = *pB++;
691	                sum += inA1 * inB1;
692	                colCnt--;
693	            }
694	
695	            sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
696	            *pOut++ = NDS_DSP_SAT((sum >> post_rshift), 8);
697	        }
698	    }
