65	            vint8m8_t vpBuffer2 = __riscv_vand(__riscv_vundefined_i8m8(), 0, vl);   //zero
66	            while(len > 0)
67	            {
68	                __riscv_vse8(pBuffer2, vpBuffer2, vl);
69	                len -= vl;
70	                pBuffer2 += vl;
71	                vl = __riscv_vsetvl_e8m8(len);
72	            }
73	
74	            // if (i_ker_y < 0)
75	            for (i_ker_y = i_out_y * stride - pad; i_ker_y < 0; i_ker_y++)
76	            {
77	                pBuffer += ker_dim * 3;
