99	                    pBuffer += vl;
100	                    loop -= vl;
101	                }
102	
103	                // if (i_ker_x >= in_tensor_dim)
104	                for ( ; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
