746	    q31_t *pwt2 = (q31_t *)wt_tmp_buf;
747	    for (i = 0; i < out_tensor_ch; i++)
748	    {
749	        size = size2;
750	        while (size != 0)
751	        {
752	            tmp = *__SIMD32(wt_tmp)++;;
753	            *pwt2++ = NDS_DSP_SUNPKD810(tmp);
754	            *pwt2++ = NDS_DSP_SUNPKD810(tmp >> 16);
755	            size--;
756	        }
757	        q7_t tmp1 = *wt_tmp++;
758	        q7_t tmp2 = *wt_tmp++;
759	        *pwt2++ = NDS_DSP_PKBB16(tmp2, tmp1);
760	        tmp1 = *wt_tmp++;
761	        *pwt2++ = (u16_t)tmp1;
762	    }
763	
764	    // This part implements the im2col function
765	    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
766	    {
767	        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
768	        {
769	            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
770	            {
771	                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
772	                {
773	                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
774	                    {
775	                        *pBuffer++ = 0;
776	                        *pBuffer++ = 0;
777	                        *pBuffer++ = 0;
778	                    }
779	                    else
780	                    {
781	                        const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
782	                        *pBuffer++ = *pPixel++;
783	                        *pBuffer++ = *pPixel++;
784	                        *pBuffer++ = *pPixel++;
785	                    }
786	                }
787	            }
