793	                pBuffer = in_tmp_buf;
794	            }
795	        }
796	    }
797	
798	    if (pBuffer != in_tmp_buf)
799	    {
800	        const q7_t *pA = ker_weight;
801	        int i;
802	
803	        for (i = 0; i < out_tensor_ch; i++)
804	        {
805	            q31_t   sum = 0;
806	            q15_t   *pB = in_tmp_buf;
807	
808	            /* basically each time it process 4 entries */
809	            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 2;
810	
811	            while (colCnt)
812	            {
813	                q31_t     inA1, inA2;
814	                q31_t     inB1, inB2;
815	
816	                pA = (q7_t *) read_and_pad((void *)pA, &inA1, &inA2);
817	                inB1 = *__SIMD32(pB)++;
818	                sum = NDS_DSP_KMADA(sum, inA1, inB1);
819	                inB2 = *__SIMD32(pB)++;
820	                sum = NDS_DSP_KMADA(sum, inA2, inB2);
821	
822	                colCnt--;
823	            }
824	            colCnt = 3 * ker_dim * ker_dim & 0x3;
825	            while (colCnt)
826	            {
827	                q7_t      inA1 = *pA++;
828	                q15_t     inB1 = *pB++;
829	                sum += inA1 * inB1;
830	                colCnt--;
831	            }
832	
833	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
834	            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
835	        }
836	    }
837	#else
838	    uint16_t  i, j, k, l, m, n;
839	    int       conv_out;
840	    long in_row, in_col;
841	
842	    for (i = 0; i < out_tensor_ch; i++)
843	    {
844	        for (j = 0; j < out_tensor_dim; j++)
845	        {
846	            for (k = 0; k < out_tensor_dim; k++)
847	            {
848	                conv_out = 0;
849	                for (m = 0; m < ker_dim; m++)
850	                {
851	                    for (n = 0; n < ker_dim; n++)
852	                    {
853	                        /* if-for implementation */
854	                        in_row = stride * j + m - pad;
855	                        in_col = stride * k + n - pad;
856	                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim && in_col < in_tensor_dim)
857	                        {
858	                            for (l = 0; l < 3; l++)
859	                            {
860	                                conv_out +=
861	                                    in_tensor[(in_row * in_tensor_dim + in_col) * 3 + l]
862	                                    * ker_weight[i * 3 * ker_dim * ker_dim + (m * ker_dim + n) * 3 + l];
863	                            }
864	                        }
865	                    }
866	                }
867	                conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
868	                out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = NDS_ISA_SATS((conv_out >> post_rshift), 8);
869	            }
870	        }
871	    }
872	#endif
873	
874	    return 0;
875	}
