                                                         out_tensor_ch,
                                                         pre_rshift,
                                                         out_scale,
                                                         post_rshift,
                                                         tiling_size);
                /* reset */
                col_counter = 0;
                pBuffer = (u8_t *)in_tmp_buf;
            }
        }
    }

    /* check if there is left-over for compute */
    pOut = nn_mat_mul_kernel_tiling_u8_u8_s8((u8_t*)in_tmp_buf,
